section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/greenfield-infra-decision-matrix.json",
  "type": "object",
  "required": [
    "project_id",
    "decision_date",
    "revisit_due_date",
    "axes",
    "constraints",
    "signoffs"
  ],
  "properties": {
    "project_id": {
      "type": "string",
      "description": "string"
    },
    "decision_date": {
      "type": "string",
      "description": "string"
    },
    "revisit_due_date": {
      "type": "string",
      "description": "string"
    },
    "axes": {
      "type": "array",
      "description": "array (each {axis, candidates, red_flags_applied, scores, chosen, rationale})"
    },
    "constraints": {
      "type": "object",
      "description": "object (compliance, budget, scale, team)"
    },
    "signoffs": {
      "type": "array",
      "description": "array (each {role, name, date})"
    }
  }
}

example.code:
{
  "project_id": "acme-q3-2026-platform",
  "decision_date": "2026-05-15",
  "revisit_due_date": "2027-05-15",
  "axes": [
    {
      "axis": "container_orchestrator",
      "candidates": [
        "EKS",
        "ECS",
        "Cloud Run"
      ],
      "red_flags_applied": [
        "Cloud Run requires GCP \u2014 disqualifies if AWS-only"
      ],
      "scores": {
        "EKS": 4,
        "ECS": 3,
        "Cloud Run": 0
      },
      "chosen": "EKS",
      "rationale": "Team familiar with k8s; ECS lacks ecosystem; Cloud Run disqualified by AWS-only constraint."
    }
  ],
  "constraints": {
    "compliance": "SOC2 + HIPAA",
    "budget_monthly_usd": 8000,
    "scale_users": 50000,
    "team_skills": [
      "k8s",
      "aws"
    ]
  },
  "signoffs": [
    {
      "role": "engineering_leader",
      "name": "Alice",
      "date": "2026-05-15"
    }
  ]
}
